#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int a,b,c; scanf("%d %d %d",&a,&b,&c);
        int pos=0, neg=0;
        if(a>0) pos++; else if(a<0) neg++;
        if(b>0) pos++; else if(b<0) neg++;
        if(c>0) pos++; else if(c<0) neg++;
        if(pos>0 && neg>0) printf("YES\n"); else printf("NO\n");
    }
    return 0;
}

